    </section>
    <!-- Küte ja ventilatsioon -->
    <section class="w-full border-y border-primary-100 my-20">
      <div class="text-center border-b border-primary-100 py-6">
        <h2>{{$t('Küte ja ventilatsioon')}}</h2>
      </div>
      <div class="max-w-screen-xl mx-auto px-3 xl:px-0 py-10">
        <div class="space-y-3">
          <h3 class="text-2xl">{{$t('Küte ja sisekliima')}}</h3>
          <p>
            {{$t('Hoone on ühendatud piirkonna kaugküttesüsteemiga. Ruumipõhiselt reguleeritav vesipõrandaküte tagab mugava ja energiasäästliku sisekliima. Küttetorustike kollektorkapid on paigaldatud esiku kappi või majapidamise ruumi. Kvaliteetse ja säästliku õhuvahetuse ning siseõhu tagab korterite ja äripindade individuaalse seadmega soojustagastusega sundventilatsioonisüsteem. Köögikubude jaoks on paigaldatud väljatõmbekanalid.')}}
          </p>
        </div>
      </div>
    </section>
